<script setup lang="ts">
import * as z from 'zod'; import type { FormSubmitEvent } from '@nuxt/ui'
const challenge = useState<{ session: string, username: string } | null>('password-change-challenge', () => null); const schema = z.object({ username: z.string().min(1), password: z.string().min(8) }); type Schema = z.output<typeof schema>; const state = reactive<Partial<Schema>>({ username: challenge.value?.username || '', password: '' }); const error = ref(challenge.value ? '' : 'Password change session is missing. Sign in again.')
async function submit(event: FormSubmitEvent<Schema>) { try { if (!challenge.value) throw new Error('Password change session is missing. Sign in again.'); const result = await $fetch<{ redirectTo: string }>('/api/auth/new-password', { method: 'POST', body: { password: event.data.password, session: challenge.value.session } }); challenge.value = null; await navigateTo(result.redirectTo, { external: true }) } catch (cause: any) { error.value = cause?.data?.message || cause?.message } }
</script>
<template><AuthShell title="新しいパスワードが必要です" description="仮パスワードを恒久パスワードへ変更します"><UAlert v-if="error" color="error" variant="soft" :description="error" class="mb-5" /><UForm :schema="schema" :state="state" class="space-y-5" @submit="submit"><UFormField name="username" label="ユーザー名" required><UInput v-model="state.username" class="w-full" /></UFormField><UFormField name="password" label="新しいパスワード" required><UInput v-model="state.password" type="password" class="w-full" /></UFormField><UButton type="submit" label="パスワードを変更" block size="lg" /></UForm></AuthShell></template>
